const express = require('express');
const app = express();
const router = express.Router();

router.route('/:id')
  .get((req, res) => res.send(`Get ${req.params.id}`))
  .put((req, res) => res.send(`Update ${req.params.id}`))
  .delete((req, res) => res.send(`Delete ${req.params.id}`));

app.use('/items', router);
